  /**
   * MaxConcurrent is the maximum number of in-flight deliveries. Used
   * only in ThrottleModeConcurrency. 1 means serial delivery.
   */
  max_concurrent?: number;
  /**
   * MaxQueueDepth bounds how many webhooks may sit in the queue for this
   * output. Zero means unbounded. When exceeded, the ingester rejects
   * new webhooks with HTTP 429.
   */
  max_queue_depth?: number;
  /** Mode is ThrottleModeRate or ThrottleModeConcurrency. */
